#!/usr/bin/env node
// PreToolUse hook for vibe-doc.
// Blocks edits to packages/vibe-doc/dist/ — that directory is generated by
// `npm run build` (tsc + copy-templates.js) and edits are silently overwritten.
// Wired into .claude/settings.json on Edit|Write|MultiEdit.

let input = '';
process.stdin.on('data', (chunk) => { input += chunk; });
process.stdin.on('end', () => {
  try {
    const payload = JSON.parse(input || '{}');
    const filePath = payload?.tool_input?.file_path || '';
    const normalized = filePath.replace(/\\/g, '/');
    if (/(^|\/)packages\/vibe-doc\/dist\//.test(normalized)) {
      process.stderr.write(
        `Blocked: ${filePath}\n\n` +
        `packages/vibe-doc/dist/ is generated by 'npm run build' (tsc + copy-templates.js).\n` +
        `Edit packages/vibe-doc/src/ instead, then rebuild. Edits to dist/ are silently overwritten.\n` +
        `(See CLAUDE.md "What NOT to do".)\n`
      );
      process.exit(2);
    }
  } catch {
    // fail open — guardrail, not a security boundary
  }
  process.exit(0);
});
